// AUTO-GENERATED by scripts/50_export_dashboard_data.py — do not edit by hand.
// Three tables backing the /non-accruals page:
//
//  currentNonAccruals — every NA position in the latest reliable quarter
//    per BDC. Fair value / cost / par are converted to MILLIONS of real USD.
//
//  nonAccrualFlow — per (ticker, company_norm, maturity_date) loans whose
//    status flipped between the prior and current quarter ('new_na' or
//    'cured'). Loans that stay NA quarter-over-quarter are NOT emitted
//    (they show up in currentNonAccruals instead).
//
//  crossIssuerDisagreement — borrowers held by 2+ covered BDCs in the
//    latest quarter where at least one BDC flagged the loan non-accrual
//    AND at least one did not. Useful for spotting cross-issuer mark
//    rebellions.
//
// MFIC is excluded from is_non_accrual aggregations — its SOI doesn't
// flag non-accrual at the position level.

export interface CurrentNonAccrual {
  ticker: string;
  period_end: string;
  company: string;
  company_norm: string;
  industry: string | null;
  investment_type: string | null;
  maturity_date: string | null;
  fv_m: number;       // USD millions
  cost_m: number;     // USD millions
  par_m: number;      // USD millions (0 for equity)
  mark_at_par: number | null;   // 0..1 (null when par not available)
}

export interface NonAccrualFlowEvent {
  ticker: string;
  period_end: string;          // current quarter being reported
  prior_period_end: string;
  event: "new_na" | "cured";
  company: string;
  company_norm: string;
  investment_type: string | null;
  maturity_date: string | null;
  cur_fv_m: number | null;     // fv in current quarter (null if cured & dropped)
  prv_fv_m: number | null;     // fv in prior quarter (null if new position)
  cost_m: number | null;
}

export interface CrossIssuerDisagreement {
  company_norm: string;
  display_name: string;            // most recent display variant
  period_end: string;
  n_holders: number;
  n_holders_na: number;
  total_fv_m: number;
  total_fv_na_m: number;
  holders: Array<{ ticker: string; is_non_accrual: boolean; fv_m: number; mark_at_par: number | null }>;
}

